// Parse Claude response, build HTML file, prepare GitHub payloads
const response = $input.first().json;
const raw = response.content[0].text.trim();

// Strip markdown fences if Claude added them anyway
let jsonStr = raw;
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
}

const post = JSON.parse(jsonStr);

// Sanitize slug just in case
post.slug = post.slug.toLowerCase().replace(/[^a-z0-9-]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60);

const now = new Date();
const dateIso = now.toISOString();
const dateDisplay = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const dateLastmod = dateIso.slice(0, 10);

const primaryTag = (post.tags && post.tags[0]) ? post.tags[0] : 'AI';
const tagsCsv = (post.tags || []).join(', ');

// Escape for JSON-LD and meta tags
const esc = (s) => String(s).replace(/\\/g, '\\\\').replace(/"/g, '\\"');
const escHtml = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

const template = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>${escHtml(post.title)} | Jaybird Automations Blog</title>
<meta name="description" content="${escHtml(post.meta_description)}" />
<meta name="author" content="Jaybird Automations" />
<meta name="robots" content="index, follow" />
<meta name="theme-color" content="#0a0a0f" />
<meta name="keywords" content="${escHtml(tagsCsv)}" />
<link rel="canonical" href="https://jaybirdautomations.com/blog/posts/${post.slug}.html" />
<meta property="og:type" content="article" />
<meta property="og:url" content="https://jaybirdautomations.com/blog/posts/${post.slug}.html" />
<meta property="og:title" content="${escHtml(post.title)}" />
<meta property="og:description" content="${escHtml(post.meta_description)}" />
<meta property="og:image" content="https://jaybirdautomations.com/og-image.png" />
<meta property="og:site_name" content="Jaybird Automations" />
<meta property="article:published_time" content="${dateIso}" />
<meta property="article:author" content="Jaybird Automations" />
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:title" content="${escHtml(post.title)}" />
<meta name="twitter:description" content="${escHtml(post.meta_description)}" />
<meta name="twitter:image" content="https://jaybirdautomations.com/og-image.png" />
<script type="application/ld+json">
{
  "@context": "https://schema.org",
  "@type": "Article",
  "headline": "${esc(post.title)}",
  "description": "${esc(post.meta_description)}",
  "image": "https://jaybirdautomations.com/og-image.png",
  "datePublished": "${dateIso}",
  "dateModified": "${dateIso}",
  "author": { "@type": "Organization", "name": "Jaybird Automations", "url": "https://jaybirdautomations.com/" },
  "publisher": { "@type": "Organization", "name": "Jaybird Automations", "logo": { "@type": "ImageObject", "url": "https://jaybirdautomations.com/og-image.png" } },
  "mainEntityOfPage": { "@type": "WebPage", "@id": "https://jaybirdautomations.com/blog/posts/${post.slug}.html" }
}
</script>
<script type="application/ld+json">
{
  "@context": "https://schema.org",
  "@type": "BreadcrumbList",
  "itemListElement": [
    { "@type": "ListItem", "position": 1, "name": "Home", "item": "https://jaybirdautomations.com/" },
    { "@type": "ListItem", "position": 2, "name": "Blog", "item": "https://jaybirdautomations.com/blog/" },
    { "@type": "ListItem", "position": 3, "name": "${esc(post.title)}" }
  ]
}
</script>
<script async src="https://www.googletagmanager.com/gtag/js?id=G-2PLT037V1Q"></script>
<script>window.dataLayer=window.dataLayer||[];function gtag(){dataLayer.push(arguments);}gtag('js',new Date());gtag('config','G-2PLT037V1Q');</script>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{--bg:#0a0a0f;--bg-card:#11111a;--accent:#6c63ff;--accent2:#00d4ff;--text:#e8e8f0;--muted:#888899;--border:rgba(108,99,255,0.2);--radius:14px;--max-w:760px}
html{scroll-behavior:smooth}
body{font-family:'Segoe UI',system-ui,sans-serif;background:var(--bg);color:var(--text);line-height:1.8;overflow-x:hidden}
a{color:var(--accent2);text-decoration:none}
a:hover{text-decoration:underline}
.container{max-width:var(--max-w);margin:0 auto;padding:0 24px}
.btn{display:inline-flex;align-items:center;gap:8px;padding:13px 28px;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;border:none;transition:all .25s;text-decoration:none}
.btn-primary{background:linear-gradient(135deg,var(--accent),#8b5cf6);color:#fff;box-shadow:0 0 24px rgba(108,99,255,.35)}
.btn-primary:hover{transform:translateY(-2px);box-shadow:0 0 40px rgba(108,99,255,.6)}
.btn-outline{background:transparent;color:var(--text);border:1px solid var(--border)}
.btn-outline:hover{border-color:var(--accent);color:var(--accent)}
#navbar{position:fixed;top:0;left:0;right:0;z-index:1000;padding:14px 0;background:rgba(10,10,15,.96);backdrop-filter:blur(16px);border-bottom:1px solid var(--border)}
.nav-inner{display:flex;align-items:center;justify-content:space-between;max-width:1160px;margin:0 auto;padding:0 24px}
.nav-logo{font-size:1.3rem;font-weight:800;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.nav-links{display:flex;align-items:center;gap:28px}
.nav-links a{font-size:13px;font-weight:500;color:var(--muted);transition:color .2s}
.nav-links a:hover{color:var(--text)}
.article-wrap{padding:140px 0 80px}
.breadcrumbs{font-size:13px;color:var(--muted);margin-bottom:24px}
.breadcrumbs a{color:var(--muted)}
.breadcrumbs a:hover{color:var(--accent);text-decoration:none}
.breadcrumbs span{margin:0 8px}
article h1{font-size:clamp(1.8rem,4vw,2.8rem);font-weight:800;line-height:1.2;margin-bottom:18px;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.article-meta{color:var(--muted);font-size:14px;margin-bottom:40px;display:flex;align-items:center;gap:14px;flex-wrap:wrap}
.article-meta .dot{width:4px;height:4px;background:var(--muted);border-radius:50%}
.tag{display:inline-block;background:rgba(108,99,255,0.1);border:1px solid var(--border);color:var(--accent);font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;padding:4px 10px;border-radius:100px}
article .body h2{font-size:1.6rem;font-weight:700;color:var(--text);margin:40px 0 16px;line-height:1.3}
article .body h3{font-size:1.25rem;font-weight:700;color:var(--text);margin:32px 0 12px}
article .body p{color:#c8c8d4;margin-bottom:18px;font-size:17px}
article .body ul,article .body ol{margin:18px 0 18px 24px;color:#c8c8d4}
article .body li{margin-bottom:10px;font-size:17px}
article .body a{color:var(--accent2)}
article .body strong{color:var(--text)}
.cta-box{margin-top:56px;padding:40px 32px;background:linear-gradient(135deg,rgba(108,99,255,0.12),rgba(0,212,255,0.06));border:1px solid var(--border);border-radius:var(--radius);text-align:center}
.cta-box h3{font-size:1.4rem;margin-bottom:10px;color:var(--text)}
.cta-box p{color:var(--muted);margin-bottom:22px}
.cta-actions{display:flex;gap:12px;justify-content:center;flex-wrap:wrap}
footer{border-top:1px solid var(--border);padding:32px 0;text-align:center;color:var(--muted);font-size:13px;margin-top:60px}
@media(max-width:640px){.nav-links a:not(.btn){display:none}article h1{font-size:1.7rem}}
</style>
</head>
<body>
<nav id="navbar">
<div class="nav-inner">
<a href="/" class="nav-logo">⚡ Jaybird Automations</a>
<div class="nav-links">
<a href="/#services">Services</a>
<a href="/#results">Results</a>
<a href="/blog/">Blog</a>
<a href="/#pricing">Pricing</a>
<a href="/#contact" class="btn btn-primary" style="padding:9px 20px;font-size:13px;">Book a Call</a>
</div>
</div>
</nav>
<div class="article-wrap">
<div class="container">
<nav class="breadcrumbs" aria-label="Breadcrumb">
<a href="/">Home</a><span>›</span><a href="/blog/">Blog</a><span>›</span>${escHtml(post.title)}
</nav>
<article>
<h1>${escHtml(post.title)}</h1>
<div class="article-meta">
<span>By Jaybird Automations</span>
<span class="dot"></span>
<span>${dateDisplay}</span>
<span class="dot"></span>
<span class="tag">${escHtml(primaryTag)}</span>
</div>
<div class="body">
${post.body_html}
</div>
<div class="cta-box">
<h3>Want this running for your business?</h3>
<p>Book a free discovery call — we'll map out exactly how AI can save you time and make you money.</p>
<div class="cta-actions">
<a href="/#contact" class="btn btn-primary">🚀 Book a Free Call</a>
<a href="/blog/" class="btn btn-outline">← More Posts</a>
</div>
</div>
</article>
</div>
</div>
<footer><div class="container">© ${now.getFullYear()} Jaybird Automations · Las Vegas, NV · <a href="mailto:jay@jaybirdautomations.com" style="color:var(--muted);">jay@jaybirdautomations.com</a></div></footer>
</body>
</html>`;

// Base64 encode for GitHub API
const htmlBase64 = Buffer.from(template, 'utf8').toString('base64');

return [{
  json: {
    title: post.title,
    slug: post.slug,
    excerpt: post.excerpt,
    meta_description: post.meta_description,
    tags: post.tags,
    date: dateIso,
    dateLastmod,
    html_base64: htmlBase64,
    filepath: `blog/posts/${post.slug}.html`,
    commit_message: `Blog: ${post.title}`
  }
}];

// Merge new post into posts.json
const postsFile = $input.first().json;
const postMeta = $('Build HTML').first().json;

const currentContent = Buffer.from(postsFile.content, 'base64').toString('utf8');
const current = JSON.parse(currentContent);

const newEntry = {
  title: postMeta.title,
  slug: postMeta.slug,
  excerpt: postMeta.excerpt,
  tags: postMeta.tags,
  date: postMeta.date
};

current.posts = current.posts || [];
current.posts.unshift(newEntry);

const newContent = JSON.stringify(current, null, 2) + '\n';
const newBase64 = Buffer.from(newContent, 'utf8').toString('base64');

return [{
  json: {
    sha: postsFile.sha,
    content_base64: newBase64,
    commit_message: `Blog manifest: ${postMeta.title}`
  }
}];

// Insert new post URL into sitemap.xml
const sitemapFile = $input.first().json;
const postMeta = $('Build HTML').first().json;

const current = Buffer.from(sitemapFile.content, 'base64').toString('utf8');

const newUrl = `  <!-- Blog post: ${postMeta.title} -->
  <url>
    <loc>https://jaybirdautomations.com/blog/posts/${postMeta.slug}.html</loc>
    <lastmod>${postMeta.dateLastmod}</lastmod>
    <changefreq>monthly</changefreq>
    <priority>0.8</priority>
  </url>

`;

// Insert right before </urlset>
const updated = current.replace('</urlset>', newUrl + '</urlset>');
const newBase64 = Buffer.from(updated, 'utf8').toString('base64');

return [{
  json: {
    sha: sitemapFile.sha,
    content_base64: newBase64,
    commit_message: `Sitemap: add ${postMeta.slug}`
  }
}];
